+                    .messages
+                    .iter()
+                    .filter(|m| outcome.inserted_indices.contains(&m.idx))
+                    .cloned()
+                    .collect();
+                t_index.add_messages(conv, &new_msgs)?;
+            }
+        }
+
+        Ok(())
+    }
